import React, { useState, useEffect, useRef, useCallback } from 'react'
import useData from './data';
import { useTableContext } from './Provider';

function InfiniteScroll({ children }) {
    const [page, setPage] = useState(0)

    const { loading, error, tableData, total } = useData(page)
    const { setTableData, searchedData } = useTableContext()

    const observerRef = useRef(null)
    const [isLoading, setIsLoading] = useState(false)
    const [hasMore, setHasMore] = useState(false)

    // ✅ Prevent StrictMode double-fetch side effects
    const initialLoadDone = useRef(false)

    // ✅ Push API data into context (ONLY once per new data)
    useEffect(() => {
        if (!tableData) return

        // prevent duplicate updates in StrictMode
        if (!initialLoadDone.current && page === 0) {
            initialLoadDone.current = true
        }

        setTableData(tableData)
        setIsLoading(false)
    }, [tableData])

    // ✅ Compute hasMore safely
    useEffect(() => {
        if (searchedData && total !== undefined) {
            setHasMore(searchedData.length <= total)
        }
    }, [searchedData, total])

    // ✅ Attach observer ONLY after first data is rendered
    const lastItemRef = useCallback((node) => {
        if (!node) return
        if (!hasMore || isLoading) return

        // ❗ prevent firing before first data render
        if (searchedData.length === 0) return

        if (observerRef.current) {
            observerRef.current.disconnect()
        }

        observerRef.current = new IntersectionObserver(([entry]) => {
            if (entry.isIntersecting && hasMore && !isLoading) {
                setIsLoading(true)

                // disconnect immediately to avoid duplicate triggers
                observerRef.current.disconnect()

                setPage(prev => prev + 1)
            }
        })

        observerRef.current.observe(node)

        return () => {
            if (observerRef.current) {
                observerRef.current.disconnect()
            }
        }
    }, [hasMore, isLoading, searchedData])

    return (
        <>
            {children}

            {/* ✅ sentinel */}
            <div ref={lastItemRef}>
                {isLoading && "...Loading"}
            </div>
        </>
    )
}

export default InfiniteScroll
